-----------------------------------------------------------------
---@class UIHelper
local UIHelper = LxClass("UIHelper", nil)

------------------------------------------------------------------
function UIHelper.InitTopInfo(wndInst)
	local helpBtn = wndInst.mHelpBtn
	wndInst:SetWndClick(helpBtn, function(...)
		UIHelper.OnClickHelpBtn(wndInst._sid)
	end)

	local _sid = wndInst:GetWndArg("sid")
	local data = nil
	wndInst._sid = _sid
	if not _sid then
		return
	end
	local activityData = gModelActivity:GetWebActivityDataById(_sid)
	if not activityData then
		return
	end
	local data = activityData.config

	if data then
		local path,pos,text
		path = data.image
		if LxUiHelper.IsImgPathValid(path) then
			wndInst:SetWndEasyImage(wndInst.mTop,path,nil,true)
		end
		path = data.descIcon
		pos = data.descIconPosition
		if LxUiHelper.IsImgPathValid(path) then
			wndInst:SetWndEasyImage(wndInst.mTextImg,path,function ()
				CS.ShowObject(wndInst.mTextImg,true)
			end,true)
			wndInst:SetAnchorPos(wndInst.mTextImg, LxDataHelper.ParseVector2NotEmpty(pos))
		end
		local showHelp = data.helpTips == 1
		CS.ShowObject(helpBtn,showHelp)
		pos = data.helpTipsPosition
		if showHelp then
			wndInst:SetAnchorPos(helpBtn, LxDataHelper.ParseVector2NotEmpty(pos))
		end
	end
end

function UIHelper.OnClickHelpBtn(sid)--点击帮助
	local _sid = sid
	local activityData = gModelActivity:GetWebActivityDataById(_sid)
	if not activityData then
		return
	end
	local data = activityData.config
	local title = gModelActivity:GetLngNameByActivitySid(_sid)
	local content = data.helpTipsContent
	GF.OpenWnd("UIBzTips",{title= title,text = content})
end